metadata.originalCode:
const StockChart = ({ data }) => {
  if (!data || !data.data || !data.data.length) return null;

  const company = data.name;
  const ticker = data.ticker;

  const formatDateString = (date) => {
    if (!date) return "";
    const d = new Date(date);
    return d.toLocaleString("en-US", { month: "short" });
  };

  // Combine labels and values into an array of objects for Recharts
  const chartData = data.data.map((item) => ({
    date: item.date,
    price: item.close,
  }));

  // Get the latest price for the ReferenceLine
  const latestPrice = chartData.length > 0 ? chartData[chartData.length - 1].price : null;

  return (
    <div style={{ marginTop: "2rem" }}>
      <h3>
        {company} ({ticker})
      </h3>
      <ResponsiveContainer width="100%" height={300}>
        <LineChart
          data={chartData}
          margin={{ top: 10, right: 30, left: 0, bottom: 0 }}
        >
          <XAxis
            dataKey="date"
            tick={{ fontSize: 12 }}
            tickLine
            tickFormatter={formatDateString}
          />
          <YAxis domain={["auto", "auto"]} />
          <Tooltip />
          <Legend />
          <Line type="monotone" dataKey="price" stroke="#8884d8" dot={false} />
          {latestPrice !== null && (
            <ReferenceLine
              y={latestPrice}
              label="Current Price"
              stroke="red"
              strokeDasharray="3 3"
            />
          )}
        </LineChart>
      </ResponsiveContainer>
    </div>
  );
};

export default StockChart;

